mapper.select:
SELECT id, content, metadata,
       1 - (embedding <=> #{embedding}::vector) AS score
FROM document_chunk WHERE metadata->>'baseId' = #{baseId}
ORDER BY embedding <=> #{embedding}::vector
LIMIT #{topK}

SELECT id, content, metadata,
       ts_rank_cd(content_tsv, plainto_tsquery('simple', #{query})) AS score
FROM document_chunk WHERE metadata->>'baseId' = #{baseId}
    AND content_tsv @@ plainto_tsquery('simple', #{query})
ORDER BY ts_rank_cd(content_tsv, plainto_tsquery('simple', #{query})) DESC
LIMIT #{topK}

SELECT id, content, metadata FROM document_chunk
WHERE metadata->>'baseId' = #{baseId}
ORDER BY id ASC
